#include <cstdarg>
#include <iostream>

int findMin(int count, ...)
{
    va_list args;
    va_start(args, count);
    int min{ va_arg(args, int) };
    for (int i{ 1 }; i < count; ++i)
    {
        int val{ va_arg(args, int) };
        if (val < min)
            min = val;
    }
    va_end(args);
    return min;
}

int main()
{
    int n{};
    std::cin >> n;

    int v[5]{};
    for (int i{ 0 }; i < n; ++i)
        std::cin >> v[i];

    int result{};
    if (n == 1)      result = findMin(1, v[0]);
    else if (n == 2) result = findMin(2, v[0], v[1]);
    else if (n == 3) result = findMin(3, v[0], v[1], v[2]);
    else if (n == 4) result = findMin(4, v[0], v[1], v[2], v[3]);
    else             result = findMin(5, v[0], v[1], v[2], v[3], v[4]);

    std::cout << result << '\n';

    return 0;
}
